  ('heelevel3-d0d1b9a2-moex-00585', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-110-f6c431ec', 'sub-heelevel3-d0d1b9a2-04', NULL, 'single_choice', '財產稅轉嫁與歸宿分析的傳統觀點是採部分均衡分析，認為財產稅是對土地和建築物課徵貨物 稅。有關傳統觀點超額負擔的說明，下列何者正確？', '["土地稅和房屋稅都會造成超額負擔", "土地稅和房屋稅都不會造成超額負擔", "只有土地稅會造成超額負擔，房屋稅則否", "只有房屋稅會造成超額負擔，土地稅則否"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:03+00:00", "source_pdf_sha1": "13fea319c49b", "answer_pdf_sha1": "816865504eb7", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
